(function(){var t=localStorage.getItem("theme");if(!t)t=window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light";document.documentElement.setAttribute("data-theme",t)})();document.addEventListener("DOMContentLoaded",function(){document.getElementById("theme-toggle").addEventListener("click",function(){var html=document.documentElement;var next=html.getAttribute("data-theme")==="dark"?"light":"dark";html.setAttribute("data-theme",next);localStorage.setItem("theme",next)})});